#include <iostream>
#include <string>
#include <vector>

// Implement DynString: owns a heap-allocated C-string and follows the Rule of
// Five. Add two static counters -- one incremented in the move constructor,
// one in the copy constructor -- and expose them via moveCount()/copyCount().
// main below is fixed and shows the required interface.

int main()
{
    std::string word{};
    int n{};
    std::cin >> word >> n;

    DynString original{ word.c_str() };

    std::vector<DynString> log{};
    log.reserve(2 * n);

    for (int i{ 0 }; i < n; ++i)
        log.push_back(DynString{ word.c_str() }); // move-construct from a temporary

    for (int i{ 0 }; i < n; ++i)
        log.push_back(original); // copy-construct from a named l-value

    log.back().setChar(0, '*'); // mutate only the last copy

    std::cout << "moves: " << DynString::moveCount() << '\n';
    std::cout << "copies: " << DynString::copyCount() << '\n';
    log.front().print();  // a moved element: text intact
    log.back().print();   // the mutated copy
    original.print();     // unchanged original

    return 0;
}

