#include <iostream>
#include <vector>

// Implement MatrixRow: owns a heap-allocated double[] and follows the Rule of
// Five (deep-copy on copy, steal-and-null on move). Add two static counters --
// one incremented in the move constructor, one in the copy constructor -- and
// expose moveCount()/copyCount(). main below is fixed.

int main()
{
    int size{};
    double val{};
    int k{};
    std::cin >> size >> val >> k;

    MatrixRow base{ size };
    for (int j{ 0 }; j < size; ++j)
        base.set(j, val);

    std::vector<MatrixRow> rows{};
    rows.reserve(2 * k);

    for (int i{ 0 }; i < k; ++i) // move-construct from temporaries
    {
        rows.push_back(MatrixRow{ size });
        for (int j{ 0 }; j < size; ++j)
            rows.back().set(j, val);
    }

    for (int i{ 0 }; i < k; ++i) // copy-construct from a named l-value
        rows.push_back(base);

    rows.back().set(0, 999); // mutate only the last copy

    std::cout << "moves: " << MatrixRow::moveCount() << '\n';
    std::cout << "copies: " << MatrixRow::copyCount() << '\n';
    rows.front().print(); // a moved row: data intact
    rows.back().print();  // the mutated copy
    base.print();         // unchanged base

    return 0;
}

