#include <iostream>
#include <vector>
class MatrixRow {
    double* m_data{}; int m_size{};
    static inline int s_moves{0}; static inline int s_copies{0};
public:
    MatrixRow() = default;
    MatrixRow(int size): m_data{ new double[size]{} }, m_size{size} {}
    ~MatrixRow(){ delete[] m_data; }
    MatrixRow(const MatrixRow& src): m_data{ src.m_size>0 ? new double[src.m_size] : nullptr }, m_size{src.m_size}{
        ++s_copies; for(int i=0;i<m_size;++i) m_data[i]=src.m_data[i];
    }
    MatrixRow& operator=(const MatrixRow& src){
        if(this!=&src){ ++s_copies; delete[] m_data; m_size=src.m_size; m_data=m_size>0?new double[m_size]:nullptr; for(int i=0;i<m_size;++i) m_data[i]=src.m_data[i]; }
        return *this;
    }
    MatrixRow(MatrixRow&& src) noexcept : m_data{src.m_data}, m_size{src.m_size}{ ++s_moves; src.m_data=nullptr; src.m_size=0; }
    MatrixRow& operator=(MatrixRow&& src) noexcept {
        if(this!=&src){ ++s_moves; delete[] m_data; m_data=src.m_data; m_size=src.m_size; src.m_data=nullptr; src.m_size=0; }
        return *this;
    }
    void set(int i,double v){ m_data[i]=v; }
    int size() const { return m_size; }
    void print() const { for(int i=0;i<m_size;++i){ if(i>0) std::cout<<' '; std::cout<<m_data[i]; } std::cout<<'\n'; }
    static int moveCount(){ return s_moves; } static int copyCount(){ return s_copies; }
};
int main(){
    int size{}; double val{}; int k{};
    std::cin >> size >> val >> k;
    MatrixRow base{ size }; for(int j=0;j<size;++j) base.set(j,val);
    std::vector<MatrixRow> rows; rows.reserve(2*k);
    for(int i=0;i<k;++i){ rows.push_back(MatrixRow{ size }); for(int j=0;j<size;++j) rows.back().set(j,val); }
    for(int i=0;i<k;++i) rows.push_back(base);
    rows.back().set(0,999);
    std::cout << "moves: " << MatrixRow::moveCount() << '\n';
    std::cout << "copies: " << MatrixRow::copyCount() << '\n';
    rows.front().print(); rows.back().print(); base.print();
    return 0;
}
